/* ==========================================================================
   SKIN: Windows XP (Luna)   ·   [data-skin="xp"]
   Skeuomorphic beveled controls, putty greys, navy title gradient. Derived
   from bosphorify.com. Pure CSS over stock shadcn (+ the generic shell).
   ========================================================================== */

:root[data-skin="xp"] {
  --app-font-sans: "Tahoma", "Verdana", "Geneva", "DejaVu Sans", "Segoe UI", sans-serif;
  --app-font-heading: var(--app-font-sans);
  --app-font-mono: "Lucida Console", "DejaVu Sans Mono", "Courier New", monospace;
  --app-font-size: 13px;

  --radius: 0px;

  --background: #d4d0c8;
  --foreground: #000000;
  --card: #ece9d8;
  --card-foreground: #000000;
  --popover: #ffffff;
  --popover-foreground: #000000;
  --primary: #0a246a;
  --primary-foreground: #ffffff;
  --secondary: #ece9d8;
  --secondary-foreground: #000000;
  --muted: #d4d0c8;
  --muted-foreground: #555555;
  --accent: #316ac5;
  --accent-foreground: #ffffff;
  --destructive: #a40000;
  --border: #808080;
  --input: #808080;
  --ring: #0a246a;
  --chart-1: #0a246a;
  --chart-2: #3a6ea5;
  --chart-3: #1f8a1f;
  --chart-4: #c08000;
  --chart-5: #a40000;
  --sidebar: #ece9d8;
  --sidebar-foreground: #000000;
  --sidebar-accent: #316ac5;
  --sidebar-accent-foreground: #ffffff;
  --sidebar-border: #808080;

  --xp-face: #ece9d8;
  --xp-desktop: #d4d0c8;
  --xp-selection: #316ac5;
  --xp-hilite: #ffffff;
  --xp-shadow: #808080;
  --xp-shadow-deep: #404040;

  --xp-bevel-raised:
    inset 1px 1px 0 0 var(--xp-hilite),
    inset -1px -1px 0 0 var(--xp-shadow-deep),
    inset 2px 2px 0 0 #f7f6f0,
    inset -2px -2px 0 0 var(--xp-shadow);
  --xp-bevel-sunken:
    inset 1px 1px 0 0 var(--xp-shadow-deep),
    inset -1px -1px 0 0 var(--xp-hilite),
    inset 2px 2px 0 0 var(--xp-shadow),
    inset -2px -2px 0 0 #f7f6f0;
  --xp-bevel-field:
    inset 1px 1px 0 0 var(--xp-shadow),
    inset -1px -1px 0 0 var(--xp-hilite),
    inset 2px 2px 0 0 var(--xp-shadow-deep),
    inset -2px -2px 0 0 #f7f6f0;
  --xp-bevel-window:
    inset 1px 1px 0 0 var(--xp-hilite),
    inset -1px -1px 0 0 var(--xp-shadow);
}

[data-skin="xp"] body {
  background: var(--xp-desktop);
  font-size: 13px;
}
[data-skin="xp"] ::selection { background: var(--xp-selection); color: #fff; }

/* ---- Shell → window chrome --------------------------------------------- */
[data-skin="xp"] .app {
  max-width: 1000px;
  padding: 28px 16px 40px;
}
[data-skin="xp"] .app-bar {
  background: var(--xp-face);
  border: 0;
  border-radius: 0;
  box-shadow: var(--xp-bevel-window);
  backdrop-filter: none;
  margin-bottom: 10px;
  padding: 4px 8px;
}
[data-skin="xp"] .app-brand { font-weight: 700; }

[data-skin="xp"] .stage {
  background: var(--xp-face);
  border: 1px solid #00138c;
  box-shadow: inset 0 0 0 1px #0a246a, 3px 3px 10px rgba(0, 0, 0, 0.35);
}
[data-skin="xp"] .stage-head {
  display: flex;
  padding: 3px 4px 3px 7px;
  color: #fff;
  font-weight: 700;
  font-size: 12px;
  background: linear-gradient(to right, #0a246a, #3a6ea5);
  border-bottom: 1px solid #00138c;
}
[data-skin="xp"] .stage-head-buttons span {
  width: 17px;
  height: 15px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 10px;
  line-height: 1;
  color: #000;
  background: #d4d0c8;
  border: 1px solid;
  border-color: #fff #404040 #404040 #fff;
}
[data-skin="xp"] .app-main { padding: 10px; gap: 10px; }
[data-skin="xp"] .app-nav { top: 84px; }
[data-skin="xp"] .app-nav-inner {
  background: #fff;
  border: 0;
  border-radius: 0;
  box-shadow: var(--xp-bevel-field);
  padding: 2px;
  gap: 0;
}
[data-skin="xp"] .app-nav-title {
  color: #fff;
  background: linear-gradient(to right, #0a246a, #3a6ea5);
  text-transform: none;
  letter-spacing: 0;
  font-weight: 700;
  padding: 2px 8px;
  margin: -2px -2px 2px;
}
[data-skin="xp"] .app-nav a { border-radius: 0; font-size: 12px; padding: 3px 8px; }
[data-skin="xp"] .app-nav a:hover { background: var(--xp-selection); color: #fff; }

[data-skin="xp"] .gallery { gap: 8px; }

[data-skin="xp"] .hero {
  background: #000;
  border: 0;
  border-radius: 0;
  box-shadow: var(--xp-bevel-field);
  padding: 16px;
}
[data-skin="xp"] .hero-kicker { color: #00ff00; font-weight: 700; font-size: 16px; }
[data-skin="xp"] .hero-title { display: none; }
[data-skin="xp"] .hero-sub { color: #cccccc; font-family: var(--app-font-mono); font-size: 12.5px; }

/* Specimen → XP task panel with gradient caption */
[data-skin="xp"] .specimen {
  border: 1px solid var(--xp-shadow);
  border-radius: 0;
  background: var(--xp-face);
  box-shadow: inset 1px 1px 0 0 #fff;
}
[data-skin="xp"] .specimen-head {
  padding: 2px 8px;
  color: #fff;
  border-bottom: 0;
  background: linear-gradient(to right, #0a246a, #3a6ea5);
  box-shadow: inset 0 1px 0 0 rgba(255, 255, 255, 0.22);
}
[data-skin="xp"] .specimen-title { font-size: 11px; font-weight: 700; }
[data-skin="xp"] .specimen-tag {
  font-size: 10px;
  font-style: italic;
  color: #cdd8ec;
}
[data-skin="xp"] .specimen-body { padding: 14px; }

[data-skin="xp"] .app-status {
  border: 0;
  border-radius: 0;
  background: var(--xp-face);
  border-top: 1px solid #fff;
  box-shadow: none;
  color: #333;
  margin-top: 0;
  padding: 2px 3px;
  gap: 3px;
}
[data-skin="xp"] .app-status > * {
  padding: 1px 8px;
  box-shadow: inset 1px 1px 0 0 var(--xp-shadow), inset -1px -1px 0 0 #fff;
}

/* ---- Controls ----------------------------------------------------------- */
[data-skin="xp"] .group\/button {
  border: 0;
  border-radius: 0;
  background-color: var(--xp-face);
  color: #000;
  box-shadow: var(--xp-bevel-raised);
  transition: none;
}
[data-skin="xp"] .group\/button:hover { background-color: #f4f2e9; }
[data-skin="xp"] .group\/button:active:not(:disabled),
[data-skin="xp"] .group\/button[data-state="open"],
[data-skin="xp"] .group\/button[aria-expanded="true"] {
  box-shadow: var(--xp-bevel-sunken);
}
[data-skin="xp"] .group\/button:focus-visible {
  outline: 1px dotted #000;
  outline-offset: -4px;
  box-shadow: var(--xp-bevel-raised);
}
[data-skin="xp"] .group\/button[data-variant="default"] { font-weight: 700; }
[data-skin="xp"] .group\/button[data-variant="destructive"] { color: var(--destructive); }
[data-skin="xp"] .group\/button[data-variant="link"] {
  background: transparent; box-shadow: none; color: #0000ee; text-decoration: underline;
}
[data-skin="xp"] .group\/button[data-variant="ghost"] { background: transparent; box-shadow: none; }
[data-skin="xp"] .group\/button[data-variant="ghost"]:hover { background: var(--xp-selection); color: #fff; }

[data-skin="xp"] [data-slot="input"],
[data-skin="xp"] [data-slot="textarea"],
[data-skin="xp"] [data-slot="select-trigger"],
[data-skin="xp"] .skin-select {
  border: 0;
  border-radius: 0;
  background-color: #fff;
  color: #000;
  box-shadow: var(--xp-bevel-field);
}
[data-skin="xp"] [data-slot="input"]:focus-visible,
[data-skin="xp"] [data-slot="textarea"]:focus-visible,
[data-skin="xp"] [data-slot="select-trigger"]:focus-visible {
  outline: 1px dotted #0a246a;
  outline-offset: -3px;
}

[data-skin="xp"] [data-slot="card"] {
  border: 0;
  border-radius: 0;
  background-color: var(--xp-face);
  box-shadow: var(--xp-bevel-window);
}

[data-skin="xp"] [data-slot="popover-content"],
[data-skin="xp"] [data-slot="dropdown-menu-content"],
[data-skin="xp"] [data-slot="context-menu-content"],
[data-skin="xp"] [data-slot="menubar-content"],
[data-skin="xp"] [data-slot="select-content"],
[data-skin="xp"] [data-slot="command"],
[data-skin="xp"] [data-slot="hover-card-content"] {
  border: 1px solid var(--xp-shadow);
  border-radius: 0;
  box-shadow: inset 1px 1px 0 0 #fff, 2px 2px 0 0 rgba(0, 0, 0, 0.35);
  background-color: #fff;
}
[data-skin="xp"] [data-slot="tooltip-content"] {
  border-radius: 0;
  background-color: #ffffe1;
  color: #000;
  border: 1px solid #000;
}
[data-skin="xp"] [data-slot="tooltip-content"] svg { fill: #ffffe1; }

[data-skin="xp"] [data-slot="dropdown-menu-item"][data-highlighted],
[data-skin="xp"] [data-slot="context-menu-item"][data-highlighted],
[data-skin="xp"] [data-slot="select-item"][data-highlighted],
[data-skin="xp"] [data-slot="command-item"][data-selected="true"] {
  border-radius: 0;
  background-color: var(--xp-selection);
  color: #fff;
}

[data-skin="xp"] [data-slot="dialog-content"],
[data-skin="xp"] [data-slot="alert-dialog-content"],
[data-skin="xp"] [data-slot="sheet-content"] {
  border-radius: 0;
  background-color: var(--xp-face);
  border: 2px solid;
  border-color: #fff #808080 #808080 #fff;
  box-shadow: 3px 3px 0 0 rgba(0, 0, 0, 0.4);
}

[data-skin="xp"] [data-slot="checkbox"] {
  border: 0;
  border-radius: 0;
  background-color: #fff;
  box-shadow: var(--xp-bevel-field);
  color: #0a246a;
}
[data-skin="xp"] [data-slot="radio-group-item"] {
  border: 0;
  background-color: #fff;
  box-shadow:
    inset 1px 1px 0 0 var(--xp-shadow),
    inset -1px -1px 0 0 #fff,
    0 0 0 1px var(--xp-shadow-deep);
  color: #0a246a;
}

[data-skin="xp"] [data-slot="tabs-list"] {
  border-radius: 0;
  background: transparent;
  gap: 2px;
  padding: 0;
  align-items: flex-end;
  border-bottom: 1px solid var(--xp-shadow);
}
[data-skin="xp"] [data-slot="tabs-trigger"] {
  border-radius: 0;
  color: #000;
  padding: 3px 12px;
  background: linear-gradient(to bottom, #f6f4ec, var(--xp-face));
  border: 1px solid var(--xp-shadow);
  border-bottom: 0;
  box-shadow: inset 1px 1px 0 0 #fff;
  margin-top: 2px;
}
[data-skin="xp"] [data-slot="tabs-trigger"][data-state="active"] {
  background: var(--xp-face);
  position: relative;
  z-index: 1;
  margin-top: 0;
  margin-bottom: -1px;
  padding-bottom: 4px;
  font-weight: 700;
}

[data-skin="xp"] [data-slot="switch"] { border-radius: 9999px; box-shadow: var(--xp-bevel-field); }
[data-skin="xp"] [data-slot="badge"] { border-radius: 0; }

[data-skin="xp"] [data-slot="progress"] {
  border-radius: 0; background-color: #fff; box-shadow: var(--xp-bevel-field);
}
[data-skin="xp"] [data-slot="progress-indicator"] { border-radius: 0; background-color: #1f8a1f; }

[data-skin="xp"] [data-slot="slider-track"] {
  border-radius: 0; box-shadow: var(--xp-bevel-field); background-color: #fff;
}
[data-skin="xp"] [data-slot="slider-thumb"] {
  border-radius: 0; background-color: var(--xp-face); box-shadow: var(--xp-bevel-raised); border: 0;
}
